+                },
+                tooltip: {
+                    backgroundColor: CHART_THEME.tooltipBg,
+                    titleColor: CHART_THEME.fg,
+                    bodyColor: CHART_THEME.fg,
+                    borderColor: CHART_THEME.borderColor,
+                    borderWidth: 1,
+                    padding: 12
+                }
+            },
+            scales: {
+                x: {
+                    beginAtZero: true,
+                    grid: {
+                        color: CHART_THEME.gridColor
+                    },
+                    ticks: {
