+    /* Shadow */
+    --bv-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
+}
+
+/* Dark Theme (Dracula-inspired) - via .dark class */
+.dark {
+    --bv-bg: #0a0a0a;
+    --bv-bg-secondary: #171717;
