+    height: 12px;
+    border-radius: 50%;
+    flex-shrink: 0;
+}
+
+/* Stats grid */
+.bv-stats {
+    display: grid;
+    grid-template-columns: repeat(auto-fit, minmax(100px, 1fr));
+    gap: var(--bv-space-sm);
+}
+
+.bv-stat {
+    background: var(--bv-bg);
+    padding: var(--bv-space-md);
+    border-radius: var(--bv-radius-sm);
