+}
+
+.bv-stat-value {
+    font-size: 1.5rem;
+    font-weight: 600;
+    color: var(--bv-green);
+}
+
+.bv-stat-label {
+    font-size: 0.75rem;
+    color: var(--bv-fg-muted);
+    margin-top: var(--bv-space-xs);
+}
+
+/* Buttons */
+.bv-btn {
+    display: inline-flex;
+    align-items: center;
+    justify-content: center;
+    gap: var(--bv-space-xs);
+    padding: var(--bv-space-sm) var(--bv-space-md);
+    background: var(--bv-purple);
+    color: var(--bv-bg);
+    border: none;
+    border-radius: var(--bv-radius-sm);
