+    line-height: 1.6;
+}
+
+/* Headings */
+.prose h1, .prose h2, .prose h3, .prose h4, .prose h5, .prose h6 {
+    color: var(--bv-fg);
+    font-weight: 600;
+    line-height: 1.3;
+    margin-top: 1.5em;
+    margin-bottom: 0.5em;
+}
+
+.prose h1 { font-size: 1.5em; }
+.prose h2 { font-size: 1.25em; border-bottom: 1px solid var(--bv-border); padding-bottom: 0.3em; }
+.prose h3 { font-size: 1.125em; }
+.prose h4 { font-size: 1em; }
+
+.prose h1:first-child, .prose h2:first-child, .prose h3:first-child {
+    margin-top: 0;
+}
+
+/* Paragraphs */
+.prose p {
+    margin-top: 0.75em;
+    margin-bottom: 0.75em;
+}
+
+.prose p:first-child {
+    margin-top: 0;
+}
+
+/* Links */
+.prose a {
+    color: var(--bv-cyan);
+    text-decoration: none;
+    font-weight: 500;
+    transition: color 0.15s ease;
+}
+
+.prose a:hover {
+    color: var(--bv-purple);
+    text-decoration: underline;
+}
+
+/* Bold and emphasis */
+.prose strong {
+    color: var(--bv-fg);
+    font-weight: 600;
+}
+
+.prose em {
+    font-style: italic;
+}
+
+/* Code */
+.prose code {
+    font-family: var(--bv-font-mono);
+    font-size: 0.875em;
+    background: var(--bv-bg-secondary);
+    color: var(--bv-pink);
