+    border-radius: 4px;
+    font-weight: 500;
+}
+
+.prose pre {
+    font-family: var(--bv-font-mono);
+    font-size: 0.8125rem;
+    line-height: 1.5;
+    background: var(--bv-bg-tertiary);
+    color: var(--bv-fg);
+    padding: 1em;
+    border-radius: 8px;
+    overflow-x: auto;
+    margin: 1em 0;
+    border: 1px solid var(--bv-border);
+}
+
+.prose pre code {
+    background: transparent;
+    color: inherit;
+    padding: 0;
+    font-size: inherit;
+}
+
+/* Lists */
+.prose ul, .prose ol {
+    margin: 0.75em 0;
+    padding-left: 1.5em;
+}
+
+.prose ul {
+    list-style-type: disc;
+}
+
+.prose ol {
+    list-style-type: decimal;
+}
+
+.prose li {
+    margin: 0.375em 0;
+    padding-left: 0.25em;
+}
+
+.prose li > ul, .prose li > ol {
+    margin-top: 0.375em;
+    margin-bottom: 0.375em;
+}
+
+/* Nested lists */
+.prose ul ul {
+    list-style-type: circle;
+}
+
+.prose ul ul ul {
+    list-style-type: square;
+}
+
+/* Task lists (checkboxes) */
+.prose input[type="checkbox"] {
+    margin-right: 0.5em;
+    accent-color: var(--bv-green);
+}
+
+/* Blockquotes */
+.prose blockquote {
+    border-left: 4px solid var(--bv-purple);
+    margin: 1em 0;
+    padding: 0.75em 1em;
+    color: var(--bv-fg-muted);
+    font-style: italic;
+    background: var(--bv-bg-secondary);
+    border-radius: 0 8px 8px 0;
+}
+
+.prose blockquote p {
+    margin: 0;
+}
+
+/* Horizontal rules */
+.prose hr {
+    border: none;
+    height: 1px;
+    background: var(--bv-border);
+    margin: 1.5em 0;
+}
+
+/* Tables */
+.prose table {
+    width: 100%;
+    border-collapse: collapse;
+    margin: 1em 0;
+    font-size: 0.875em;
+}
+
+.prose th, .prose td {
+    border: 1px solid var(--bv-border);
+    padding: 0.5em 0.75em;
+    text-align: left;
+}
+
+.prose th {
+    background: var(--bv-bg-secondary);
+    font-weight: 600;
+}
+
+.prose tr:nth-child(even) {
+    background: var(--bv-bg-secondary);
+}
+
+/* Images */
+.prose img {
+    max-width: 100%;
+    height: auto;
+    border-radius: 8px;
+    margin: 1em 0;
+}
+
+/* Dark mode adjustments */
+.dark .prose {
+    color: var(--bv-fg);
+}
+
+.dark .prose code {
+    background: var(--bv-bg-tertiary);
+    color: var(--bv-pink);
+}
+
+.dark .prose pre {
+    background: #1e1f29;
+    border-color: var(--bv-border);
+}
+
+.dark .prose blockquote {
+    background: var(--bv-bg-tertiary);
+    border-left-color: var(--bv-purple);
+}
+
+/* prose-invert class for explicit dark styling */
+.prose-invert {
+    color: #f8f8f2;
+}
+
+.prose-invert a {
+    color: #8be9fd;
+}
+
+.prose-invert a:hover {
+    color: #4ade80;
+}
+
+.prose-invert code {
+    background: #21222c;
+    color: #ff79c6;
+}
+
+/* Max width override */
+.prose.max-w-none {
+    max-width: none;
+}
+
+/* Heading size override for detail pane */
+.prose-headings\:text-base h1,
+.prose-headings\:text-base h2,
+.prose-headings\:text-base h3 {
+    font-size: 1rem;
+}
+
+/* Tighter paragraph spacing for detail pane */
+.prose-p\:my-2 p {
+    margin-top: 0.5rem;
+    margin-bottom: 0.5rem;
+}
+
+/* Prose excerpt styles for issue list inline markdown */
+.prose-excerpt {
+    /* Inherit font settings */
+    font-size: inherit;
+    line-height: inherit;
+    color: inherit;
+}
+.prose-excerpt a {
+    color: var(--bv-beads-500, #0ea5e9);
+    text-decoration: underline;
+    text-decoration-thickness: 1px;
+    text-underline-offset: 2px;
+}
+.prose-excerpt a:hover {
+    color: var(--bv-beads-600, #0284c7);
+}
+.prose-excerpt code {
+    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
+    font-size: 0.9em;
+    padding: 0.1em 0.3em;
