+    height: 8px;
+    border-radius: 4px;
+    overflow: hidden;
+    background: #f3f4f6;
+    gap: 1px;
+}
+
+.dark .score-breakdown-bar {
+    background: #374151;
+}
+
+.score-breakdown-segment {
+    height: 100%;
+    transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);
+    position: relative;
+}
+
+/* Segment hover effect */
+@media (hover: hover) {
+    .score-breakdown-segment:hover {
+        filter: brightness(1.1);
+        transform: scaleY(1.3);
+    }
+}
+
+/* Individual breakdown item rows */
+.breakdown-row {
+    display: flex;
+    align-items: center;
+    gap: 12px;
+    padding: 8px 0;
+}
+
+.breakdown-label {
+    display: flex;
+    align-items: center;
+    gap: 6px;
+    width: 100px;
+    flex-shrink: 0;
+}
+
+.breakdown-label-icon {
+    font-size: 14px;
+}
+
+.breakdown-label-text {
+    font-size: 12px;
+    font-weight: 500;
+    color: #6b7280;
+}
+
+.dark .breakdown-label-text {
+    color: #9ca3af;
+}
+
+.breakdown-bar-container {
+    flex: 1;
+    height: 10px;
+    background: #f3f4f6;
+    border-radius: 5px;
+    overflow: hidden;
+}
+
+.dark .breakdown-bar-container {
+    background: #374151;
+}
+
+.breakdown-bar-fill {
+    height: 100%;
+    border-radius: 5px;
+    transition: width 0.5s cubic-bezier(0.16, 1, 0.3, 1);
+}
+
+.breakdown-value {
+    width: 48px;
+    text-align: right;
+    font-size: 12px;
+    font-weight: 600;
+    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
+    color: #6b7280;
+    flex-shrink: 0;
+}
+
+.dark .breakdown-value {
+    color: #9ca3af;
+}
+
+/* ============================================================================
+   VELOCITY CHART ENHANCEMENTS
+   ============================================================================ */
+
+.velocity-chart {
+    display: flex;
+    align-items: flex-end;
+    gap: 4px;
+    height: 64px;
+    padding: 0 4px;
+}
+
+.velocity-bar-wrapper {
+    flex: 1;
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+    gap: 4px;
+}
+
+.velocity-bar {
+    width: 100%;
+    min-height: 4px;
+    border-radius: 4px 4px 0 0;
+    transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);
+    position: relative;
+}
+
+.velocity-bar::after {
+    content: attr(data-value);
+    position: absolute;
+    bottom: calc(100% + 4px);
+    left: 50%;
+    transform: translateX(-50%);
+    font-size: 9px;
+    font-weight: 600;
+    opacity: 0;
+    transition: opacity 0.2s ease;
+    white-space: nowrap;
+}
+
+.velocity-bar:hover::after {
+    opacity: 1;
+}
+
+.velocity-bar:hover {
+    filter: brightness(1.1);
+}
+
+.velocity-label {
+    font-size: 8px;
+    color: #9ca3af;
+    font-weight: 500;
+}
+
+/* ============================================================================
+   GLASSMORPHISM CARD VARIANT
+   ============================================================================ */
+
+.card-glass {
+    background: rgba(255, 255, 255, 0.8);
+    backdrop-filter: blur(12px);
+    -webkit-backdrop-filter: blur(12px);
+    border: 1px solid rgba(255, 255, 255, 0.3);
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.08);
+}
+
+.dark .card-glass {
+    background: rgba(31, 41, 55, 0.8);
+    border-color: rgba(255, 255, 255, 0.1);
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
+}
+
+/* ============================================================================
+   PREMIUM BUTTON STYLES
+   ============================================================================ */
+
+.btn-premium {
+    display: inline-flex;
+    align-items: center;
+    justify-content: center;
+    gap: 8px;
+    padding: 12px 20px;
+    font-size: 14px;
+    font-weight: 600;
+    border-radius: 12px;
+    transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
+    -webkit-tap-highlight-color: transparent;
+    cursor: pointer;
+    border: none;
+    outline: none;
+}
+
+.btn-premium:active {
+    transform: scale(0.97);
+}
+
+.btn-premium:focus-visible {
+    box-shadow: 0 0 0 3px rgba(34, 197, 94, 0.3);
+}
+
+.btn-premium-primary {
+    background: linear-gradient(135deg, #22c55e 0%, #16a34a 100%);
+    color: white;
+    box-shadow: 0 4px 14px rgba(34, 197, 94, 0.4);
+}
+
+.btn-premium-primary:hover {
+    box-shadow: 0 6px 20px rgba(34, 197, 94, 0.5);
+    transform: translateY(-1px);
+}
+
+.btn-premium-secondary {
+    background: rgba(0, 0, 0, 0.05);
+    color: #374151;
+}
+
+.dark .btn-premium-secondary {
+    background: rgba(255, 255, 255, 0.1);
+    color: #e5e7eb;
+}
+
+.btn-premium-secondary:hover {
+    background: rgba(0, 0, 0, 0.08);
+}
+
+.dark .btn-premium-secondary:hover {
+    background: rgba(255, 255, 255, 0.15);
+}
+
+/* ============================================================================
+   ANIMATION KEYFRAMES
+   ============================================================================ */
+
+@keyframes tooltip-enter {
+    from {
+        opacity: 0;
+        transform: translateY(8px) scale(0.96);
+    }
+    to {
+        opacity: 1;
+        transform: translateY(0) scale(1);
+    }
+}
+
+@keyframes sheet-enter {
+    from {
+        opacity: 0;
+        transform: translateY(100%);
+    }
+    to {
+        opacity: 1;
+        transform: translateY(0);
+    }
+}
+
+@keyframes pulse-glow {
+    0%, 100% {
+        box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.4);
+    }
+    50% {
+        box-shadow: 0 0 0 8px rgba(34, 197, 94, 0);
+    }
+}
+
+.animate-pulse-glow {
+    animation: pulse-glow 2s infinite;
+}
+
+/* ============================================================================
+   RESPONSIVE GRID UTILITIES
+   ============================================================================ */
+
+.insights-grid {
+    display: grid;
+    gap: 16px;
+}
+
+/* 1 column on mobile */
+@media (max-width: 640px) {
+    .insights-grid {
+        grid-template-columns: 1fr;
+    }
+}
+
+/* 2 columns on tablet */
+@media (min-width: 641px) and (max-width: 1023px) {
+    .insights-grid {
+        grid-template-columns: repeat(2, 1fr);
+    }
+}
+
+/* 4 columns on desktop */
+@media (min-width: 1024px) {
+    .insights-grid {
+        grid-template-columns: repeat(4, 1fr);
+        gap: 20px;
+    }
+
+    .insights-grid .metric-panel-expanded {
+        grid-column: span 2;
+    }
+}
+
+/* =============================================================================
+   Reduced Motion Support - Accessibility
+   ============================================================================= */
+@media (prefers-reduced-motion: reduce) {
+    *,
